// NODE 2: Validation & Enrichment

const item = $input.first().json;

// Only validate the fields that actually exist in your form
const required = [
  'Client Name',
  'Company',
  'Email',
  'Incident Type',
  'Affected Asset',
  'Urgency',
  'Description'
];

for (const field of required) {
  if (!item[field] || item[field].toString().trim() === '') {
    throw new Error(`Validation failed: Missing required field "${field}".`);
  }
}

// Validate email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(item['Email'])) {
  throw new Error('Validation failed: Invalid email format.');
}

const now = new Date();
const incidentId = `INC-${now.getTime().toString(36).toUpperCase()}`;

return [{
  json: {
    ...item,

    'Incident ID': incidentId,
    'Timestamp': now.toISOString(),
    'Current Date': now.toDateString(),
    'Analyst': 'Automated SOC',

    'Client Name': item['Client Name'].trim(),
    'Company': item['Company'].trim(),
    'Email': item['Email'].trim(),
    'Incident Type': item['Incident Type'].trim(),
    'Affected Asset': item['Affected Asset'].trim(),
    'Urgency': item['Urgency'].toUpperCase(),
