const playbook = playbooks[item['Incident Type']] || playbooks['Malware'];

// Deterministic Priority Calculation
let priority = 'Low';
const risk = playbook.riskScore;
const urgency = item['Urgency'];

if (urgency === 'CRITICAL' || risk >= 90) priority = 'Critical';
else if (urgency === 'HIGH' || risk >= 70) priority = 'High';
else if (urgency === 'MEDIUM' || risk >= 40) priority = 'Medium';
else priority = 'Low';

return [{
  json: {
    ...item,
    ...playbook,
    'Priority': priority,
    'Status': 'Triage Complete'
  }
}];

